import {START, SUCCESS} from '../types'

export default (store) => (next) => (action) => {
    const {callAPI, ...rest} = action
    if (!callAPI) next(rest)

    next({...rest, type: rest.type + START})
    fetch(callAPI)
        .then(res => res.json())
        .then(response => next({...rest, type: rest.type + SUCCESS, response}))
        .catch(e => {})
}
